INSERT INTO public."cleaning_rules" ("id", "rule_code", "rule_name", "description", "is_enabled", "priority", "config", "created_at", "updated_at") VALUES ('1eab596b-dd0b-4d2e-8ee1-65de2b66b85d'::uuid, 'morning_if_same_day', NULL, 'Programmer le ménage le matin (7h) si une nouvelle réservation arrive le jour du ménage', TRUE, 15, '{"hour":"07h00","time":"morning"}'::jsonb, '2026-01-15T11:13:24.827689+00:00', '2026-01-15T11:42:16.887039+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public."cleaning_rules" ("id", "rule_code", "rule_name", "description", "is_enabled", "priority", "config", "created_at", "updated_at") VALUES ('2128779a-06cd-4988-9a29-4f7c1f65f3da'::uuid, 'avoid_holidays', NULL, 'Reporter le ménage au jour ouvrable suivant si c''est un jour férié (sauf enchainement)', TRUE, 20, '{"postpone_if_holiday":true,"unless_same_day_checkin":true}'::jsonb, '2026-01-15T11:13:24.827689+00:00', '2026-01-15T11:42:17.918329+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public."cleaning_rules" ("id", "rule_code", "rule_name", "description", "is_enabled", "priority", "config", "created_at", "updated_at") VALUES ('b3b05a9b-7043-4d69-bd04-d4e3d18ebba1'::uuid, 'sunday_postpone', NULL, 'Reporter le ménage au lundi si départ un dimanche (sauf enchainement)', TRUE, 30, '{"postpone_to":"monday","morning_if_checkin":true,"unless_same_day_checkin":true}'::jsonb, '2026-01-15T11:13:24.827689+00:00', '2026-01-15T11:42:18.685896+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public."cleaning_rules" ("id", "rule_code", "rule_name", "description", "is_enabled", "priority", "config", "created_at", "updated_at") VALUES ('9eceb1e5-368f-4016-9f09-517d0232ad70'::uuid, 'saturday_conditional', NULL, 'Reporter au lundi si pas de réservation samedi/dimanche, sinon ménage le samedi', TRUE, 35, '{"postpone_to":"monday","check_weekend_bookings":true,"keep_if_weekend_booking":true}'::jsonb, '2026-01-15T11:13:24.827689+00:00', '2026-01-15T11:42:19.582242+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public."cleaning_rules" ("id", "rule_code", "rule_name", "description", "is_enabled", "priority", "config", "created_at", "updated_at") VALUES ('8944343d-fee1-4df3-8663-86cf3ab3755f'::uuid, 'midweek_conditional', NULL, 'Reporter au vendredi si pas de réservation avant, sinon jour même', TRUE, 40, '{"days":["wednesday","thursday"],"postpone_to":"friday","unless_booking_before":true}'::jsonb, '2026-01-15T11:13:24.827689+00:00', '2026-01-15T11:42:20.215661+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public."cleaning_rules" ("id", "rule_code", "rule_name", "description", "is_enabled", "priority", "config", "created_at", "updated_at") VALUES ('aba7c164-eb08-4840-b444-a8ec8291e892'::uuid, 'avoid_weekends', NULL, 'Reporter le ménage en semaine si départ un week-end et pas d''enchainement', TRUE, 50, '{"postpone_weekend":true,"unless_same_day_checkin":true}'::jsonb, '2026-01-15T11:13:24.827689+00:00', '2026-01-15T11:42:21.090955+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public."cleaning_rules" ("id", "rule_code", "rule_name", "description", "is_enabled", "priority", "config", "created_at", "updated_at") VALUES ('cfc97133-c590-47d2-9f24-474275955800'::uuid, 'same_day_checkin', NULL, 'Si une nouvelle réservation commence le jour du départ, faire le ménage entre les deux', TRUE, 1, '{"time":"between_checkout_checkin","default_time":"12h00"}'::jsonb, '2026-01-15T11:13:24.827689+00:00', '2026-01-22T16:35:01.993569+00:00') ON CONFLICT DO NOTHING;
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('135bcd3e-3bcb-4d97-ab49-28102e64b1ac'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Le ménage est-il inclus dans le tarif ?', NULL, 0, '2026-02-18T15:08:46.172971+00:00', '2026-02-18T15:08:46.172971+00:00', 'Bonne nouvelle : le ménage est entièrement inclus dans le prix de votre séjour, sans aucun supplément ni mauvaise surprise à la fin ! Vous n''avez donc rien à prévoir de ce côté-là, nous nous occupons de tout.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('f2b62ec0-7215-4b79-b5d7-4ebb74986234'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '655e201e-f0ae-40a1-90d7-1dd7876e5d97'::uuid, 'Où puis-je me garer ?', NULL, 0, '2026-02-18T15:00:38.842441+00:00', '2026-02-18T15:00:38.842441+00:00', 'Pas d''inquiétude pour le stationnement ! Deux parkings publics sont situés à proximité immédiate du gîte. Bonne nouvelle : ils sont entièrement gratuits, sans limitation de durée, vous n''avez donc aucune contrainte à prévoir de ce côté-là.', 'Where can I park?', 'No worries about parking! Two public car parks are located in the immediate vicinity of the cottage. Good news: they are completely free, with no time limit, so you have no constraints to expect on this side.', NULL, 0, 'arrivee') ON CONFLICT DO NOTHING;
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('34b3eb3a-1936-4eb9-8d65-fed8b3012d25'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '2ee6c0bb-1a6a-4490-85e6-af75a1ff3f03'::uuid, 'Où puis-je me garer ?', NULL, 0, '2026-02-18T15:00:07.209107+00:00', '2026-02-18T15:00:07.209107+00:00', 'Vous bénéficiez d''une cour privative pouvant accueillir jusqu''à 5 véhicules, ce qui est idéal pour les séjours en groupe ou en famille.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('5eae28b7-db66-4288-971d-dd0c427b5226'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Comment se passe la remise des clés ? Y a-t-il une arrivée autonome possible ?', NULL, 0, '2026-02-18T14:57:49.082434+00:00', '2026-02-18T14:57:49.082434+00:00', 'Oui, l''arrivée autonome est tout à fait possible et très simple à mettre en place ! Voici comment cela se passe :
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('c7150724-d91f-45ce-afe8-3feacfed8b73'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Quelles sont les heures d''arrivée et de départ ?', NULL, 0, '2026-02-18T14:53:19.492491+00:00', '2026-02-18T14:53:19.492491+00:00', 'Nos horaires standards sont les suivants : arrivée à partir de 17h et départ avant 10h. Ces créneaux nous permettent d''assurer le ménage et la préparation du gîte entre deux séjours.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('1fb4fc41-b5c0-4667-ad32-95cb7ce60635'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Le gîte est-il équipé pour les bébés (lit parapluie, chaise haute) ?', NULL, 0, '2026-02-18T15:14:06.969573+00:00', '2026-02-18T15:14:06.969573+00:00', 'Oui, nous pensons aux plus petits ! Le gîte est équipé d''un lit bébé et d''une chaise haute pour accueillir vos tout-petits dans les meilleures conditions.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('71579748-56f6-4ecc-9a6f-3b9b09e85baa'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Peut-on fumer dans le gîte ?', NULL, 0, '2026-02-18T15:11:23.013563+00:00', '2026-02-18T15:11:23.013563+00:00', 'Il est strictement interdit de fumer à l''intérieur du gîte, afin de garantir un séjour agréable pour tous les voyageurs.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('6339bd51-af3c-41a3-aaf3-009db8d0a83a'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '655e201e-f0ae-40a1-90d7-1dd7876e5d97'::uuid, 'Quelle est la capacité maximale du gîte ?', NULL, 0, '2026-02-18T15:17:42.38921+00:00', '2026-02-18T15:17:42.38921+00:00', 'Le gîte dispose de 11 couchages, ce qui correspond à sa capacité idéale pour un séjour confortable. Nous tolérons la présence de personnes supplémentaires en journée, à condition que le nombre total de personnes présentes ne dépasse jamais 15, dormants ou non.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('65c4f6c7-34f3-454c-9051-389b83a1bf2e'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Les fêtes et événements sont-ils autorisés ?', NULL, 0, '2026-02-18T15:13:00.026927+00:00', '2026-02-18T15:13:00.026927+00:00', 'Oui, vous pouvez tout à fait organiser une fête ou un événement dans le gîte, dans le respect de quelques règles simples !
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('2f6c3ab5-c58b-4f37-933e-3272b4fae7ca'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '2ee6c0bb-1a6a-4490-85e6-af75a1ff3f03'::uuid, 'Y a-t-il un barbecue ?', NULL, 0, '2026-02-18T15:25:45.160801+00:00', '2026-02-18T15:25:45.160801+00:00', 'Pas de barbecue traditionnel, mais mieux encore : le gîte est équipé d''une plancha à gaz pour des repas conviviaux et savoureux en extérieur !
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('6ee9023e-409a-4699-82df-65885ade62bb'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '2ee6c0bb-1a6a-4490-85e6-af75a1ff3f03'::uuid, 'Le gîte est-il accessible aux personnes à mobilité réduite ?', NULL, 0, '2026-02-18T15:22:49.932442+00:00', '2026-02-18T15:22:49.932442+00:00', 'Le gîte de Trévoux ne répond pas aux normes officielles d''accessibilité handicapés, mais il offre néanmoins de bonnes conditions pour les personnes ayant des difficultés de mobilité. En effet, une chambre, une salle de bain ainsi que le séjour sont situés au rez-de-chaussée, permettant de limiter au maximum les déplacements en escalier.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('493a2c10-b9f0-4062-a2bc-1e939db64891'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '655e201e-f0ae-40a1-90d7-1dd7876e5d97'::uuid, 'Le gîte est-il accessible aux personnes à mobilité réduite ?', NULL, 0, '2026-02-18T15:22:31.391862+00:00', '2026-02-18T15:22:31.391862+00:00', 'Le gîte de Couzon est malheureusement difficile d''accès pour les personnes à mobilité réduite, le séjour principal étant situé à l''étage. Nous vous conseillons de nous contacter avant votre réservation afin que nous puissions évaluer ensemble si le gîte correspond à vos besoins et contraintes.', 'Is the campsite accessible for those with impaired mobility?', 'The cottage of Couzon is unfortunately difficult to access for people with reduced mobility, the main living room being located upstairs. We advise you to contact us before your reservation so that we can assess together if the cottage corresponds to your needs and constraints.', NULL, 0, 'autre') ON CONFLICT DO NOTHING;
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('f8f54017-b678-48c3-aed5-303acb78dc53'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '2ee6c0bb-1a6a-4490-85e6-af75a1ff3f03'::uuid, 'Y a-t-il des règles de bruit ou des horaires de tranquillité ?', NULL, 0, '2026-02-18T15:28:04.288586+00:00', '2026-02-18T15:28:04.288586+00:00', 'Oui, afin de préserver la tranquillité du voisinage et de garantir un séjour agréable pour tous, nous vous demandons de respecter quelques règles simples à partir de 22h :
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('4ea424c2-757c-45d3-b3e9-e81ea1259e37'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '655e201e-f0ae-40a1-90d7-1dd7876e5d97'::uuid, 'Comment rejoindre le gîte en transports en commun ?', NULL, 0, '2026-02-18T15:34:27.090156+00:00', '2026-02-18T15:34:27.090156+00:00', 'Le gîte est très bien desservi par les transports en commun TCL !
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('f3ce01ef-0533-48a0-b8db-bbce412de340'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Le gîte est-il adapté pour des vacances en famille avec enfants ou avec des personnes âgées ?', NULL, 0, '2026-02-18T15:31:09.236488+00:00', '2026-02-18T15:31:09.236488+00:00', 'Absolument ! Nous avons vraiment plaisir à accueillir les familles et les groupes d''amis, et mettons un point d''honneur à ce que chacun, petits et grands, se sente à l''aise et bien accueilli.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('9d5ce530-a0b4-4130-98d3-403f04ce5d28'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Les animaux de compagnie sont-ils acceptés ?', NULL, 0, '2026-02-18T15:10:05.713418+00:00', '2026-02-18T15:10:05.713418+00:00', 'Oui, nous acceptons les animaux de compagnie sur demande ! N''hésitez pas à nous en informer lors de votre réservation afin que nous puissions valider votre séjour ensemble.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('e55db76b-b2cc-446d-906d-a47a0fd97511'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Le linge de maison est-il fourni ?', NULL, 0, '2026-02-18T15:04:34.530824+00:00', '2026-02-18T15:04:34.530824+00:00', 'Oui, le linge de maison est entièrement fourni ! Vous trouverez à votre disposition draps et serviettes pour tout votre séjour, sans rien avoir à prévoir de votre côté.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('0353a629-286c-4b9a-bea7-163a3d39b093'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Dispose-t-il d''une connexion Wi-Fi ?', NULL, 0, '2026-02-18T15:19:01.398714+00:00', '2026-02-18T15:19:01.398714+00:00', 'Oui, le gîte est équipé d''une connexion Wi-Fi en fibre optique pour un accès internet rapide et fluide tout au long de votre séjour, que ce soit pour le télétravail, le streaming ou simplement rester connecté.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('b117f70b-e191-44bf-a356-fc3850a775ee'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Quelles sont les activités à faire à proximité ?', NULL, 0, '2026-02-18T15:29:50.548378+00:00', '2026-02-18T15:29:50.548378+00:00', 'Nous avons pensé à tout ! L''ensemble des activités à découvrir aux alentours du gîte est recensé et détaillé directement dans notre application. Restaurants, balades, visites, bons plans locaux... tout y est pour vous aider à profiter au maximum de votre séjour !
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('6006f592-b9f3-4cd9-b16f-8474cf84d350'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Y a-t-il une climatisation ou un chauffage ?', NULL, 0, '2026-02-18T15:21:16.285444+00:00', '2026-02-18T15:21:16.285444+00:00', 'Les gîtes sont équipés de climatisations réversibles, assurant ainsi votre confort aussi bien en été qu''en hiver !
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('83f970cd-2aa9-4127-934c-a8b175866dd6'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, '2ee6c0bb-1a6a-4490-85e6-af75a1ff3f03'::uuid, 'Quelle est la capacité maximale du gîte ?', NULL, 0, '2026-02-18T15:16:21.808236+00:00', '2026-02-18T15:16:21.808236+00:00', 'La capacité maximale du gîte est de 15 personnes. Ce nombre ne peut en aucun cas être dépassé, et ce pour des raisons importantes que nous tenons à vous expliquer.
INSERT INTO public."faq" ("id", "owner_user_id", "gite_id", "question", "categorie", "ordre", "created_at", "updated_at", "answer", "question_en", "answer_en", "reponse_en", "priority", "category") VALUES ('c4d4d0f5-343e-4343-98af-abd63ddb2520'::uuid, '12296d3d-696b-4c5d-95b7-e0b3a1dd1814'::uuid, NULL, 'Que se passe-t-il si j''oublie quelque chose sur place ?', NULL, 0, '2026-02-18T15:37:19.979171+00:00', '2026-02-18T15:37:19.979171+00:00', 'Avant toute chose, nous vous conseillons vivement de faire un tour complet du gîte avant votre départ : chambres, salles de bain, terrasse, placards... un petit passage dans chaque pièce suffit souvent à éviter les oublis !
